// setupEvaluationServer creates a gRPC gateway mux with the evaluation service
func setupEvaluationServer(t *testing.T, store evaluation.Storer) *runtime.ServeMux {
	ctx := context.Background()
	logger := zaptest.NewLogger(t)
	server := evaluation.New(logger, store)
	mux := runtime.NewServeMux()

	err := rpcevaluation.RegisterEvaluationServiceHandlerServer(ctx, mux, server)
	require.NoError(t, err)

	return mux
}

// mockStorage implements the Storer interface for testing
type mockStorage struct {
	getFlagFunc                     func(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error)
	getEvaluationRulesFunc          func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error)
	getEvaluationDistributionsFunc  func(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error)
	getEvaluationRolloutsFunc       func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error)
}

func (m *mockStorage) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	if m.getFlagFunc != nil {
		return m.getFlagFunc(ctx, req)
	}
	return nil, errs.ErrNotFound("flag not found")
}

func (m *mockStorage) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	if m.getEvaluationRulesFunc != nil {
		return m.getEvaluationRulesFunc(ctx, req)
	}
	return []*storage.EvaluationRule{}, nil
}

func (m *mockStorage) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
