// TestBatchEvaluationSuccess tests batch evaluation with mixed flag types
func TestBatchEvaluationSuccess(t *testing.T) {
	store := &mockStorage{
		getFlagFunc: func(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
			if req.GetKey() == "boolean-flag" {
				return &flipt.Flag{
					NamespaceKey: "default",
					Key:          "boolean-flag",
					Enabled:      true,
					Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
				}, nil
			}
			if req.GetKey() == "variant-flag" {
				return &flipt.Flag{
					NamespaceKey: "default",
					Key:          "variant-flag",
					Enabled:      true,
					Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
				}, nil
			}
			return nil, errs.ErrNotFound("flag not found")
		},
		getEvaluationRolloutsFunc: func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
			return []*storage.EvaluationRollout{}, nil
		},
		getEvaluationRulesFunc: func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
			return []*storage.EvaluationRule{}, nil
		},
	}

	mux := setupEvaluationServer(t, store)
	server := httptest.NewServer(mux)
	defer server.Close()

	reqBody := map[string]interface{}{
		"requests": []map[string]interface{}{
			{
				"requestId":    "1",
				"namespaceKey": "default",
				"flagKey":      "boolean-flag",
				"entityId":     "user123",
			},
			{
				"requestId":    "2",
				"namespaceKey": "default",
				"flagKey":      "variant-flag",
				"entityId":     "user123",
			},
			{
				"requestId":    "3",
				"namespaceKey": "default",
				"flagKey":      "missing-flag",
				"entityId":     "user123",
			},
		},
	}

	body, err := json.Marshal(reqBody)
	require.NoError(t, err)

	resp, err := http.Post(server.URL+"/evaluate/v1/batch", "application/json", bytes.NewReader(body))
	require.NoError(t, err)
	defer resp.Body.Close()

	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result map[string]interface{}
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	responses := result["responses"].([]interface{})
	assert.Len(t, responses, 3)

	// Check first response (boolean)
	resp1 := responses[0].(map[string]interface{})
	if boolResp, ok := resp1["booleanResponse"]; ok {
		boolData := boolResp.(map[string]interface{})
		assert.True(t, boolData["enabled"].(bool))
		assert.Equal(t, "DEFAULT_EVALUATION_REASON", boolData["reason"])
		assert.Equal(t, "1", boolData["requestId"])
	}

	// Check second response (variant)
	resp2 := responses[1].(map[string]interface{})
	if variantResp, ok := resp2["variantResponse"]; ok {
		variantData := variantResp.(map[string]interface{})
		assert.False(t, variantData["match"].(bool))
		assert.Equal(t, "2", variantData["requestId"])
	}

	// Check third response (error)
	resp3 := responses[2].(map[string]interface{})
	if errorResp, ok := resp3["errorResponse"]; ok {
		errorData := errorResp.(map[string]interface{})
		assert.Equal(t, "missing-flag", errorData["flagKey"])
		assert.Equal(t, "NOT_FOUND_ERROR_EVALUATION_REASON", errorData["reason"])
	}
}

