				Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			}, nil
		},
		getEvaluationRulesFunc: func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
			return []*storage.EvaluationRule{
				{
					ID:      "rule1",
					FlagKey: "variant-with-attachment",
					Rank:    0,
					Segments: map[string]*storage.EvaluationSegment{
						"all": {
							SegmentKey: "all",
							MatchType:  flipt.MatchType_ANY_MATCH_TYPE,
							Constraints: []storage.EvaluationConstraint{},
						},
					},
				},
			}, nil
		},
		getEvaluationDistributionsFunc: func(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
			return []*storage.EvaluationDistribution{
				{
					ID:                  "dist1",
					RuleID:              "rule1",
					VariantID:           "variant1",
					VariantKey:          "blue",
					VariantAttachment:   `{"color":"blue","percentage":50}`,
					Rollout:             100,
				},
			}, nil
		},
	}

	mux := setupEvaluationServer(t, store)
	server := httptest.NewServer(mux)
	defer server.Close()

	reqBody := map[string]interface{}{
		"namespaceKey": "default",
		"flagKey":      "variant-with-attachment",
		"entityId":     "user123",
